const QUIZ_BANK_P2 = {
  6: [
    // Multiple Choice (35)
    { type: 'mc', q: "Which OSHA standard covers machine guarding requirements for power-driven machinery?", options: ["29 CFR 1926.100", "29 CFR 1926.300", "29 CFR 1926.502", "29 CFR 1926.200"], a: 1, explain: "1926.300 requires all power-driven machinery to have appropriate guards.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "What is a 'nip point' in the context of machine hazards?", options: ["A pinch point where two moving parts approach each other", "The highest point of a rotating drum", "An area below a suspended load", "The edge of an excavation"], a: 0, explain: "Nip points occur where rotating or moving parts come together, creating a caught-in hazard.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Before performing maintenance on any machinery, workers must follow which procedure?", options: ["Slow the machine to idle speed", "Lockout/Tagout (LOTO)", "Wear extra-thick gloves", "Ask a supervisor to watch"], a: 1, explain: "Lockout/Tagout (LOTO) procedures must be followed before any maintenance to prevent unexpected energization.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Which caught-in/between scenario is considered the most deadly on construction sites?", options: ["Caught in rotating auger", "Caught between two vehicles", "Excavation cave-in", "Caught in concrete mixer"], a: 2, explain: "Excavation cave-ins are the most deadly caught-in/between scenario due to the massive weight of soil.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "A worker operating a crane should ensure that other workers stay out of what area?", options: ["The operator cab", "The counterweight swing radius exclusion zone", "The area directly in front of the crane", "Within 50 feet of the crane"], a: 1, explain: "Workers must stay out of the crane's counterweight arc/swing radius exclusion zone to avoid being struck or caught between.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Which of the following personal items should NEVER be worn near rotating equipment?", options: ["Steel-toed boots", "Loose clothing and jewelry", "Safety glasses", "Hard hats"], a: 1, explain: "Loose clothing, jewelry, and long hair can be caught in rotating equipment, causing severe injury.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "What type of hazard is created when a worker's body part is squeezed between two objects?", options: ["Struck-by hazard", "Pinch point hazard", "Electrical hazard", "Fall hazard"], a: 1, explain: "Pinch points occur when a body part is caught between two objects, creating a caught-between hazard.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "A rollover of a compact excavator can result in what type of caught-in/between injury?", options: ["Operator caught between the machine and the ground", "Operator falling from height", "Operator struck by a falling object", "Operator caught in rotating auger"], a: 0, explain: "A rollover creates a caught-between hazard where the operator can be trapped between the machine and the ground.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Workers should NEVER work under which of the following?", options: ["An overhead ladder", "An unsupported load", "A temporary roof", "A supported scaffold"], a: 1, explain: "Working under unsupported loads creates a caught-under/struck-by hazard if the load falls or shifts.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Which piece of trenching equipment poses a significant caught-in hazard?", options: ["Laser level", "Chain-type trenching machine", "Surveying transit", "Compaction plate"], a: 1, explain: "Chain-type trenching machines have exposed rotating chains that can catch clothing or body parts.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "What is a 'wrap point' hazard on construction equipment?", options: ["A hazard where a rope becomes tangled", "A rotating shaft or component that can wind up clothing or limbs", "A point where two ladders overlap", "A defect in scaffolding planks"], a: 1, explain: "Wrap points are rotating components such as shafts or spindles that can wind up and entangle loose clothing or body parts.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "If a coworker's hand becomes caught in a running concrete mixer, the FIRST action should be:", options: ["Pull the worker free immediately", "Call 911 and wait", "Shut down and lock out the mixer before attempting rescue", "Lubricate the mechanism to free the hand"], a: 2, explain: "Shut down and lock out the machine before any rescue attempt to prevent further injury.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "The point where two counter-rotating rollers come together is known as a:", options: ["Shear point", "Nip point", "Crush zone", "Pinch arc"], a: 1, explain: "A nip point is where two rotating parts (such as rollers) come together, pulling objects into the gap.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Under 29 CFR 1926.300, who is responsible for ensuring machinery guards are in place?", options: ["The worker operating the machine", "The employer", "OSHA inspectors only", "The machinery manufacturer"], a: 1, explain: "The employer is responsible for ensuring all power-driven machinery has appropriate guards per 1926.300.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "A drill auger presents which type of caught-in/between hazard?", options: ["Struck-by hazard only", "Wrap point and rotating equipment hazard", "Cave-in hazard", "Electrical hazard"], a: 1, explain: "A drill auger is a rotating component creating a wrap point hazard that can catch loose clothing or body parts.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Which of the following is the safest practice when working around rotating machinery?", options: ["Use gloves with loose-fitting cuffs for grip", "Tie back long hair and remove loose jewelry before work", "Work quickly to minimize exposure time", "Keep at least 5 feet away at all times"], a: 1, explain: "Tying back hair and removing loose jewelry prevents them from being caught in rotating components.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "What is a shear point?", options: ["The angle at which a blade cuts most efficiently", "The point where two parts move across each other in opposite directions, creating a cutting action", "The maximum load a shoring system can support", "The depth at which a trench requires shoring"], a: 1, explain: "A shear point occurs where two parts move in opposite directions across each other, creating a hazardous cutting or shearing action.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "How should a worker approach a stopped machine before beginning maintenance?", options: ["Verify the machine is off by touching a moving part", "Apply LOTO to prevent unexpected startup, then verify zero energy state", "Simply turn off the power switch", "Wait 5 minutes after shutdown"], a: 1, explain: "LOTO must be applied and zero energy state verified before any maintenance to protect against unexpected energization.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Caught-in/between hazards on construction sites most commonly result in injuries to which body parts?", options: ["Feet and ankles", "Hands, fingers, and arms", "Eyes and face", "Ears and neck"], a: 1, explain: "Hands, fingers, and arms are most commonly injured in caught-in/between incidents due to their proximity to machinery during work.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "What type of guard completely encloses a dangerous part of a machine?", options: ["Barrier guard", "Two-hand control", "Interlock guard", "Enclosure guard"], a: 3, explain: "An enclosure guard completely surrounds or encloses a dangerous machine part to prevent contact.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "When is it acceptable to remove a machine guard to improve work efficiency?", options: ["When a supervisor approves it", "When wearing double gloves", "Never — guards must remain in place during operation", "When the task takes less than 5 minutes"], a: 2, explain: "Machine guards must never be removed during operation. They may only be removed for maintenance after LOTO is applied.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Which hazard is created when a worker is pinned between a piece of equipment and a stationary object such as a wall?", options: ["Struck-by hazard", "Caught-between hazard", "Fall hazard", "Caught-in hazard"], a: 1, explain: "Being pinned between equipment and a stationary object is a classic caught-between hazard.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Protective systems for excavations must be designed by a licensed Professional Engineer when the trench is deeper than:", options: ["4 feet", "10 feet", "20 feet", "15 feet"], a: 2, explain: "Excavations deeper than 20 feet require a protective system designed by a registered Professional Engineer.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "What should a worker do if they notice a machine guard is missing or damaged?", options: ["Continue working carefully", "Report it to the supervisor and do not operate the machine until repaired", "Improvise a temporary guard", "Use the machine only for short periods"], a: 1, explain: "Missing or damaged guards must be reported immediately, and the machine must not be used until the guard is repaired or replaced.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "What is the primary danger of running machinery near open excavations?", options: ["Noise pollution for nearby workers", "Vibrations can cause trench walls to collapse, creating a cave-in hazard", "Exhaust fumes collecting in the trench", "Electrical interference with survey equipment"], a: 1, explain: "Vibrations from nearby machinery can destabilize excavation walls, dramatically increasing the risk of cave-in.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "A competent person must inspect excavations:", options: ["Weekly", "Monthly", "Daily, before workers enter", "Only after rainstorms"], a: 2, explain: "A competent person must inspect excavations daily and before workers enter to ensure safe conditions.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Which of these is NOT a category of caught-in/between hazards?", options: ["Caught in rotating machinery", "Caught between two objects", "Caught under a cave-in", "Caught by electrical current"], a: 3, explain: "Electrical hazards are a separate category. Caught-in/between includes rotating machinery, pinch points, and cave-ins.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "If a worker must clear a jam in a conveyor belt, what must happen first?", options: ["Slow the belt to minimum speed", "Apply lockout/tagout to de-energize the conveyor", "Use a long stick to remove the jam", "Wear extra-thick gloves"], a: 1, explain: "Lockout/tagout must be applied to fully de-energize the conveyor before attempting to clear a jam.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "During demolition operations, workers risk being caught between:", options: ["Debris and the ground", "Workers and supervisors", "PPE and skin", "Tools and materials"], a: 0, explain: "Demolition creates risks of workers being caught between falling debris and the ground or other objects.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Why is long hair a hazard near rotating machinery?", options: ["It blocks vision", "It can get tangled in rotating components, pulling the worker in", "It conducts electricity", "It is a fire hazard"], a: 1, explain: "Long hair can be caught in rotating machinery and pull the worker's head or body into the equipment.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "What is the minimum safe distance workers must maintain from the edge of an excavation?", options: ["2 feet", "As far as soil conditions dictate based on competent person's assessment", "10 feet", "5 feet always"], a: 1, explain: "The safe distance from an excavation edge depends on the competent person's hazard assessment based on soil type and conditions.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Which soil type is least stable and most prone to cave-in?", options: ["Type A (hard clay)", "Type B (granular soils)", "Type C (sandy, gravelly, or unstable)", "Solid rock"], a: 2, explain: "Type C soil is the least stable, including sandy, gravelly, and submerged soils most prone to cave-in.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "In what situation is a trench box (trench shield) used?", options: ["To guide machinery along a trench line", "To protect workers from cave-in by containing the walls", "To keep surface water out of the trench", "To store tools in the trench"], a: 1, explain: "A trench box is a protective system that shields workers inside the trench from cave-in without sloping the walls.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "Which OSHA Focus Four hazard accounts for a significant percentage of caught-in/between fatalities on construction sites?", options: ["Falls", "Cave-ins", "Electrocution", "Struck-by"], a: 1, explain: "Cave-ins from excavations are a leading cause of caught-in/between fatalities in construction.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'mc', q: "What is the role of a 'competent person' in excavation safety?", options: ["Design the shoring system only", "Identify existing and predictable hazards and have authority to eliminate them", "Operate all excavating equipment", "Write the site safety plan"], a: 1, explain: "A competent person must be able to identify excavation hazards and have the authority to take corrective action.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },

    // Fill in the Blank (8)
    { type: 'fib', q: "The OSHA standard governing machine guarding for power-driven tools on construction sites is 29 CFR 1926.___.", answer: "300", accept: ["1926.300"], explain: "29 CFR 1926.300 covers general requirements for tools and machinery guarding on construction sites.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'fib', q: "Before performing maintenance on machinery, workers must apply ___ to prevent unexpected startup.", answer: "lockout/tagout", accept: ["LOTO", "lockout tagout", "lock out tag out"], explain: "Lockout/Tagout (LOTO) procedures are required before maintenance to control hazardous energy.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'fib', q: "The most deadly caught-in/between hazard on construction sites is a trench ___.", answer: "cave-in", accept: ["cave in", "collapse"], explain: "Trench cave-ins are the most deadly caught-in/between hazard due to the enormous weight of soil.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'fib', q: "Workers must stay out of a crane's counterweight ___ zone to avoid caught-between hazards.", answer: "swing radius", accept: ["swing", "exclusion", "arc"], explain: "The counterweight swing radius exclusion zone must be kept clear of all workers.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'fib', q: "A point where two rotating parts come together and create a pulling hazard is called a ___ point.", answer: "nip", accept: ["pinch", "nip point"], explain: "Nip points are created where rotating or moving parts come together, creating an area that can catch body parts.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'fib', q: "Excavations deeper than ___ feet require a protective system designed by a licensed Professional Engineer.", answer: "20", accept: ["twenty"], explain: "OSHA requires a PE-designed protective system for excavations deeper than 20 feet.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'fib', q: "Type ___ soil is the least stable and most prone to cave-in, including sandy and gravelly materials.", answer: "C", accept: ["type C", "c"], explain: "Type C is the least stable soil classification under OSHA, posing the greatest cave-in risk.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'fib', q: "Workers should never ___ wooden ladders because it can hide cracks and defects.", answer: "paint", accept: ["paint them"], explain: "Painting wooden ladders conceals defects such as cracks and splits that could cause failure.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },

    // Select All That Apply (7)
    { type: 'sa', q: "Which of the following are examples of caught-in/between hazards? (Select all that apply)", options: ["Rotating drill auger", "Unsupported trench walls", "Noise from a jackhammer", "Pinch point on a conveyor belt"], answers: [0, 1, 3], explain: "Rotating drill augers, unsupported trenches (cave-in), and pinch points are all caught-in/between hazards. Noise is a health hazard, not caught-in/between.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'sa', q: "Which of the following clothing or accessories create caught-in hazards near rotating machinery? (Select all that apply)", options: ["Loose-fitting shirt sleeves", "Steel-toed boots", "Dangling jewelry (necklace, bracelet)", "Hard hat with chin strap"], answers: [0, 2], explain: "Loose sleeves and dangling jewelry can be caught in rotating machinery. Boots and properly worn hard hats do not present this hazard.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'sa', q: "Which of the following are proper protective systems for excavations? (Select all that apply)", options: ["Sloping the trench walls", "Installing a trench box (trench shield)", "Placing spoil piles inside the trench", "Shoring the trench walls"], answers: [0, 1, 3], explain: "Sloping, trench boxes, and shoring are all acceptable protective systems. Spoil piles must be kept at least 2 feet from the trench edge, never inside.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'sa', q: "Which actions must be taken before performing maintenance on power-driven machinery? (Select all that apply)", options: ["Apply lockout/tagout (LOTO)", "Verify the machine is de-energized (zero energy state)", "Speed the machine up then let it coast to a stop", "Notify affected workers in the area"], answers: [0, 1, 3], explain: "LOTO must be applied, zero energy state verified, and affected workers notified. Speeding up a machine before maintenance is dangerous.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'sa', q: "Which of the following are types of machine hazard points that create caught-in risks? (Select all that apply)", options: ["Nip points", "Shear points", "Anchor points", "Wrap points"], answers: [0, 1, 3], explain: "Nip points, shear points, and wrap points all create caught-in hazards. Anchor points are part of fall protection systems.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'sa', q: "Which factors increase the risk of a trench cave-in? (Select all that apply)", options: ["Nearby vibrating equipment", "Previously disturbed soil", "Type A stable clay soil", "Water seepage into the trench"], answers: [0, 1, 3], explain: "Vibration, previously disturbed soil, and water seepage all increase cave-in risk. Type A soil is the most stable classification.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
    { type: 'sa', q: "Which of the following pieces of construction equipment present caught-in hazards? (Select all that apply)", options: ["Concrete mixer", "Transit level (surveying instrument)", "Chain trenching machine", "Drill auger"], answers: [0, 2, 3], explain: "Concrete mixers, chain trenching machines, and drill augers all have rotating parts creating caught-in hazards. A transit level is a non-powered instrument.", moduleRef: 6, moduleName: "Focus Four: Caught-In/Between" },
  ],

  7: [
    // Multiple Choice (35)
    { type: 'mc', q: "In the hierarchy of controls, PPE is considered the:", options: ["First line of defense", "Most effective control", "Last line of defense", "Primary engineering control"], a: 2, explain: "PPE is the last line of defense in the hierarchy of controls, used when other controls cannot adequately reduce hazards.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "Which ANSI standard governs the design and performance of industrial head protection (hard hats)?", options: ["ANSI Z87.1", "ANSI Z89.1", "ANSI/ISEA 107", "ASTM F2413"], a: 1, explain: "ANSI Z89.1 is the standard for industrial head protection, covering hard hat types and classes.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "A Type II hard hat provides protection from impacts to which areas?", options: ["Top of head only", "Top and lateral (side) impacts", "Lateral impacts only", "Bottom of head only"], a: 1, explain: "Type II hard hats protect against both top and lateral (side) impacts, unlike Type I which only covers the top.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "Which hard hat class offers NO electrical protection?", options: ["Class E", "Class G", "Class C", "Class D"], a: 2, explain: "Class C (Conductive) hard hats offer no electrical protection and should not be used in electrical hazard environments.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "A Class E hard hat is rated to protect against voltages up to:", options: ["2,200 volts", "10,000 volts", "20,000 volts", "30,000 volts"], a: 2, explain: "Class E (Electrical) hard hats are tested at 20,000 volts for high-voltage electrical work.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "Under which circumstances must a hard hat be replaced immediately?", options: ["After 5 years regardless of condition", "After any significant impact, even if no visible damage", "Only when visibly cracked", "When a new model becomes available"], a: 1, explain: "Hard hats must be replaced after any significant impact, even if there is no visible damage, as internal damage may have occurred.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "Which ANSI standard governs eye and face protection?", options: ["ANSI Z89.1", "ANSI Z87.1", "ANSI/ISEA 107", "ASTM F2413"], a: 1, explain: "ANSI Z87.1 covers the requirements for occupational and educational personal eye and face protection devices.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "When is a face shield considered sufficient eye protection on its own?", options: ["When working with chemicals", "When grinding metal", "A face shield alone is NEVER sufficient; safety glasses must be worn underneath", "When using a nail gun"], a: 2, explain: "Face shields alone do not provide adequate eye protection — safety glasses must always be worn underneath the face shield.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "When are side shields required on safety glasses?", options: ["Always when on a construction site", "When flying particles are present", "Only for outdoor work", "When using a face shield"], a: 1, explain: "Side shields are required on safety glasses when there is a danger from flying particles that could enter from the sides.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "The OSHA action level for occupational noise exposure is:", options: ["80 dBA 8-hour TWA", "85 dBA 8-hour TWA", "90 dBA 8-hour TWA", "95 dBA 8-hour TWA"], a: 1, explain: "85 dBA over an 8-hour TWA is OSHA's action level, triggering requirements for hearing conservation programs.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "The OSHA permissible exposure limit (PEL) for noise is:", options: ["85 dBA 8-hour TWA", "90 dBA 8-hour TWA", "95 dBA 8-hour TWA", "100 dBA 8-hour TWA"], a: 1, explain: "90 dBA over an 8-hour TWA is OSHA's permissible exposure limit (PEL) for noise.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "Using the doubling rule for noise, if the PEL is 90 dBA for 8 hours, at 100 dBA a worker can be exposed for:", options: ["4 hours", "2 hours", "1 hour", "30 minutes"], a: 1, explain: "Under the doubling rule, each 5 dBA increase halves the allowed exposure time. 90=8hr, 95=4hr, 100=2hr.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "To estimate actual noise attenuation in the field from hearing protection with an NRR of 30, the calculation is approximately:", options: ["30 dB of protection", "15 dB of protection (NRR/2)", "10 dB of protection", "25 dB of protection"], a: 1, explain: "Real-world protection is estimated at NRR/2, so NRR 30 provides approximately 15 dB of actual protection.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "An N95 respirator filters out what percentage of airborne particles?", options: ["90%", "95%", "99%", "99.97%"], a: 1, explain: "N95 respirators filter at least 95% of airborne particles that are 0.3 microns or larger.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "A P100 respirator filter provides what level of filtration?", options: ["95%", "99%", "99.97%", "100%"], a: 2, explain: "P100 filters remove at least 99.97% of airborne particles, providing the highest level of particulate protection.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "The Assigned Protection Factor (APF) for a half-face air-purifying respirator is:", options: ["5", "10", "25", "50"], a: 1, explain: "A half-face air-purifying respirator has an APF of 10, meaning it can reduce contaminant concentration by a factor of 10.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "Which type of respirator has an Assigned Protection Factor (APF) of 10,000?", options: ["Half-face respirator", "Full-face respirator", "SCBA (Self-Contained Breathing Apparatus)", "N95 filtering facepiece"], a: 2, explain: "An SCBA has an APF of 10,000, providing the highest level of respiratory protection.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "What is required before a worker can use a tight-fitting respirator?", options: ["OSHA certification", "Medical evaluation and fit testing", "Supervisor approval only", "A written request"], a: 1, explain: "Workers must receive a medical evaluation to ensure they are physically capable of wearing a respirator, and then pass a fit test.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "Which ASTM standard covers foot protection requirements for safety footwear?", options: ["ASTM F2413", "ASTM F1506", "ANSI Z41", "ASTM E119"], a: 0, explain: "ASTM F2413 is the standard for performance requirements for protective footwear including safety-toe and metatarsal protection.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "When would a worker need metatarsal guards in addition to steel-toed boots?", options: ["When working in wet conditions", "When heavy objects could fall on the top of the foot (metatarsal area)", "When working on scaffolding", "Always required on construction sites"], a: 1, explain: "Metatarsal guards protect the top of the foot from heavy falling objects that could crush the bones above the toes.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "ANSI/ISEA 107 Class 2 high-visibility apparel is required for workers in:", options: ["Low-traffic warehouse settings", "Roadway construction and traffic control areas", "Only nighttime work", "Indoor construction sites"], a: 1, explain: "Class 2 high-visibility garments are required for workers exposed to roadway traffic and construction areas with vehicle hazards.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "Which type of fall arrest equipment is required for personal fall arrest systems (PFAS)?", options: ["Body belt", "Full-body harness", "Chest harness", "Hip harness"], a: 1, explain: "Full-body harnesses are required for personal fall arrest systems; body belts may only be used for positioning, not arrest.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "Who is responsible for performing a workplace hazard assessment to determine necessary PPE?", options: ["The workers themselves", "The equipment manufacturer", "The employer", "OSHA inspectors"], a: 2, explain: "The employer must assess the workplace for hazards and determine what PPE is necessary to protect workers.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "Is an employer required to pay for PPE provided to employees?", options: ["No, employees must purchase their own PPE", "Yes, employers must provide most PPE at no cost to the employee", "Only if the employee requests it", "Only for PPE costing over $50"], a: 1, explain: "OSHA requires employers to provide most required PPE at no cost to employees. Some exceptions apply for items like everyday clothing.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "What does PPE training for workers NOT need to cover?", options: ["When PPE is necessary", "How to properly put on and take off PPE", "The manufacturer's profit margin for the PPE", "Limitations of the PPE"], a: 2, explain: "PPE training must cover when it's needed, how to use it, and its limitations, but not business information like manufacturer profits.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "A Class G (General) hard hat is tested to protect against voltages up to:", options: ["2,200 volts", "10,000 volts", "20,000 volts", "No electrical protection"], a: 0, explain: "Class G hard hats provide electrical protection up to 2,200 volts for lower voltage electrical work.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "How often should a worker inspect their PPE?", options: ["Monthly", "Weekly", "Before each use", "Annually"], a: 2, explain: "Workers should inspect all PPE before each use to ensure it is in good condition and will provide adequate protection.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "Which type of hearing protection typically provides the highest Noise Reduction Rating (NRR)?", options: ["Earmuffs", "Foam earplugs", "Canal caps", "They all provide the same NRR"], a: 1, explain: "Properly inserted foam earplugs typically have the highest NRR ratings, often reaching 30-33 dB under laboratory conditions.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "For respiratory protection, what is the difference between an 'N' and a 'P' filter designation?", options: ["N filters are for nitrogen, P filters are for particles", "N is not resistant to oil; P is oil-proof (resistant)", "N offers 95% filtration; P offers 100%", "There is no difference"], a: 1, explain: "N filters are not resistant to oil-based aerosols. P filters are oil-proof and can be used with oil-based contaminants.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "What is the minimum ANSI/ISEA 107 high-visibility class required for workers on or near highway rights-of-way?", options: ["Class 1", "Class 2", "Class 3", "Class 4"], a: 1, explain: "Class 2 is the minimum required for roadway construction workers to ensure adequate visibility to vehicle operators.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "Which of the following is a proper step in the hierarchy of controls BEFORE using PPE?", options: ["Elimination of the hazard", "Providing workers with better PPE", "Training workers about the hazard", "Labeling the hazard area"], a: 0, explain: "Elimination is the most effective control and sits at the top of the hierarchy, above substitution, engineering, administrative controls, and PPE.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "When using chemical protective gloves, which factor is MOST important to consider?", options: ["Glove color", "Chemical permeation resistance for the specific substance", "Glove thickness only", "Brand name"], a: 1, explain: "Gloves must be selected based on their resistance to permeation by the specific chemical being handled, as no glove protects against all chemicals.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "The full-face respirator has an Assigned Protection Factor (APF) of:", options: ["10", "25", "50", "100"], a: 2, explain: "A full-face air-purifying respirator has an APF of 50, providing greater protection than half-face models.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "How long should a hard hat be replaced even without visible damage or significant impact?", options: ["Every year", "Every 2-5 years depending on manufacturer guidelines", "Every 10 years", "They never need replacement if not damaged"], a: 1, explain: "Hard hats should be replaced every 2-5 years according to manufacturer guidelines, even without visible damage, due to material degradation.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'mc', q: "What is the purpose of a 'fit test' for respirators?", options: ["To check if the worker likes the style of the respirator", "To verify the respirator creates an adequate seal on the worker's face", "To test the filter's efficiency", "To determine if the worker needs a respirator"], a: 1, explain: "A fit test verifies that the specific respirator model creates an adequate seal on a worker's face to prevent contaminant entry.", moduleRef: 7, moduleName: "Personal Protective Equipment" },

    // Fill in the Blank (8)
    { type: 'fib', q: "PPE is considered the ___ line of defense in the hierarchy of controls.", answer: "last", accept: ["final"], explain: "PPE is the last resort after all other control measures have been implemented, as it does not eliminate the hazard.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'fib', q: "The OSHA noise action level that triggers a hearing conservation program is ___ dBA as an 8-hour TWA.", answer: "85", accept: ["85 dBA"], explain: "At 85 dBA 8-hour TWA, employers must implement a hearing conservation program including monitoring and audiometric testing.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'fib', q: "A face shield worn alone is not sufficient eye protection — safety ___ must also be worn underneath.", answer: "glasses", accept: ["safety glasses", "goggles", "eyewear"], explain: "Face shields do not provide complete eye protection and must be combined with safety glasses or goggles.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'fib', q: "To estimate real-world noise protection, divide the hearing protector's NRR by ___.", answer: "2", accept: ["two"], explain: "Real-world attenuation is estimated at NRR/2 to account for improper fit and use conditions in the field.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'fib', q: "The ANSI standard for industrial head protection (hard hats) is ANSI ___.", answer: "Z89.1", accept: ["Z89.1"], explain: "ANSI Z89.1 establishes performance and testing requirements for industrial head protection devices.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'fib', q: "For personal fall arrest systems, workers must use a full-body ___ rather than a body belt.", answer: "harness", accept: ["full-body harness"], explain: "Full-body harnesses distribute arrest forces across the body safely; body belts can cause internal injury during a fall arrest.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'fib', q: "Before using a tight-fitting respirator, a worker must complete a medical ___ and a fit test.", answer: "evaluation", accept: ["exam", "examination", "evaluation"], explain: "OSHA requires a medical evaluation to ensure the worker is medically fit to wear a respirator before fit testing.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'fib', q: "ANSI/ISEA 107 Class ___ high-visibility apparel is required for workers exposed to roadway traffic.", answer: "2", accept: ["two", "Class 2"], explain: "Class 2 high-visibility garments provide increased visibility and are required for roadway construction and traffic environments.", moduleRef: 7, moduleName: "Personal Protective Equipment" },

    // Select All That Apply (7)
    { type: 'sa', q: "Which of the following are employer responsibilities regarding PPE? (Select all that apply)", options: ["Assess workplace hazards", "Provide PPE at no cost to employees", "Allow workers to choose any PPE they prefer", "Train workers on PPE use"], answers: [0, 1, 3], explain: "Employers must assess hazards, provide PPE at no cost, and train workers. Workers must use appropriate PPE selected by hazard assessment, not personal preference.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'sa', q: "Which hard hat classes provide electrical protection? (Select all that apply)", options: ["Class C", "Class E", "Class G", "Class D"], answers: [1, 2], explain: "Class E (20,000V) and Class G (2,200V) provide electrical protection. Class C (Conductive) provides no electrical protection.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'sa', q: "Which of the following are proper reasons to replace a hard hat? (Select all that apply)", options: ["After a significant impact, even with no visible damage", "Visible cracks in the shell", "When it gets wet from rain", "After 5+ years of use per manufacturer guidelines"], answers: [0, 1, 3], explain: "Hard hats must be replaced after significant impacts, when visibly damaged, or after the manufacturer's recommended service life. Getting wet does not require replacement.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'sa', q: "Which of the following are required elements of respirator use under OSHA? (Select all that apply)", options: ["Medical evaluation before use", "Fit testing for tight-fitting respirators", "Approval from a union representative", "Written respiratory protection program"], answers: [0, 1, 3], explain: "A medical evaluation, fit testing, and a written respiratory protection program are all required by OSHA 1910.134. Union approval is not required.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'sa', q: "Which of the following are steps in the hierarchy of controls? (Select all that apply)", options: ["Elimination", "PPE", "Administrative controls", "Decoration"], answers: [0, 1, 2], explain: "Elimination, PPE, and administrative controls are all in the hierarchy (along with substitution and engineering controls). Decoration is not a control measure.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'sa', q: "When should hearing protection be worn? (Select all that apply)", options: ["When noise levels exceed 85 dBA 8-hr TWA", "When noise levels exceed 90 dBA PEL", "Whenever on any construction site regardless of noise", "When employers determine noise poses a hazard"], answers: [0, 1, 3], explain: "Hearing protection is required when noise meets or exceeds the action level (85 dBA) or PEL (90 dBA), or when the employer determines it is necessary. Not all construction sites require it.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
    { type: 'sa', q: "Which of the following factors are important when selecting chemical protective gloves? (Select all that apply)", options: ["Chemical permeation resistance", "Glove color preference", "Glove material compatibility with the chemical", "Degradation resistance to the specific chemical"], answers: [0, 2, 3], explain: "Gloves must be evaluated for permeation resistance, material compatibility, and degradation resistance for the specific chemical. Color is not a safety factor.", moduleRef: 7, moduleName: "Personal Protective Equipment" },
  ],

  8: [
    // Multiple Choice (35)
    { type: 'mc', q: "Which OSHA standard is the primary regulation for Hazard Communication (HazCom)?", options: ["29 CFR 1910.134", "29 CFR 1910.1200", "29 CFR 1926.59", "29 CFR 1910.147"], a: 1, explain: "29 CFR 1910.1200 is OSHA's Hazard Communication standard (HazCom), which applies to construction via 29 CFR 1926.59.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "What does GHS stand for in chemical safety?", options: ["Global Hazard System", "Globally Harmonized System of Classification and Labeling of Chemicals", "General Hazardous Substances standard", "Government Health and Safety standard"], a: 1, explain: "GHS stands for the Globally Harmonized System of Classification and Labeling of Chemicals, providing a standardized international approach to chemical hazard communication.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "How many mandatory sections does a Safety Data Sheet (SDS) contain?", options: ["8", "12", "16", "20"], a: 2, explain: "Under GHS-aligned HazCom, an SDS must contain exactly 16 sections covering all aspects of the chemical's hazards and safe handling.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Which SDS section contains information about required Personal Protective Equipment?", options: ["Section 4", "Section 7", "Section 8", "Section 11"], a: 2, explain: "Section 8 (Exposure Controls/PPE) contains information about occupational exposure limits and required personal protective equipment.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Which GHS signal word indicates the MORE severe hazard?", options: ["WARNING", "CAUTION", "DANGER", "NOTICE"], a: 2, explain: "DANGER is used for the more severe hazard categories. WARNING is used for less severe hazards. Only one signal word appears on a label.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "The OSHA permissible exposure limit (PEL) for respirable crystalline silica is:", options: ["25 µg/m³ 8-hr TWA", "50 µg/m³ 8-hr TWA", "100 µg/m³ 8-hr TWA", "0.1 f/cc TWA"], a: 1, explain: "The PEL for respirable crystalline silica under 1926.1153 is 50 µg/m³ as an 8-hour TWA.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "The OSHA action level for respirable crystalline silica is:", options: ["25 µg/m³ 8-hr TWA", "50 µg/m³ 8-hr TWA", "75 µg/m³ 8-hr TWA", "10 µg/m³ 8-hr TWA"], a: 0, explain: "The action level for silica is 25 µg/m³ as an 8-hour TWA, at which point employers must implement exposure control measures.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Which OSHA standard specifically covers silica exposure in construction?", options: ["29 CFR 1910.1200", "29 CFR 1926.1153", "29 CFR 1910.1000", "29 CFR 1926.62"], a: 1, explain: "29 CFR 1926.1153 is OSHA's silica standard for construction, which became effective in 2017.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Silicosis is best described as:", options: ["A reversible lung infection caused by bacteria", "Irreversible lung scarring caused by inhaling crystalline silica", "A skin condition from silica contact", "A temporary respiratory irritation"], a: 1, explain: "Silicosis is an incurable, progressive lung disease caused by inhaling fine respirable crystalline silica particles, resulting in permanent lung scarring.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "What is the OSHA PEL for asbestos fibers?", options: ["0.01 f/cc TWA", "0.1 f/cc TWA", "1.0 f/cc TWA", "10 f/cc TWA"], a: 1, explain: "The asbestos PEL is 0.1 fiber per cubic centimeter of air as an 8-hour TWA, with a STEL of 1.0 f/cc.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "The OSHA short-term exposure limit (STEL) for asbestos is:", options: ["0.1 f/cc", "0.5 f/cc", "1.0 f/cc", "5.0 f/cc"], a: 2, explain: "The asbestos STEL is 1.0 fiber per cubic centimeter over a 15-minute sampling period.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "The OSHA permissible exposure limit (PEL) for lead is:", options: ["10 µg/m³", "30 µg/m³", "50 µg/m³", "100 µg/m³"], a: 2, explain: "The lead PEL is 50 µg/m³ as an 8-hour TWA under 29 CFR 1926.62.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "The OSHA action level for lead exposure is:", options: ["10 µg/m³", "30 µg/m³", "50 µg/m³", "75 µg/m³"], a: 1, explain: "The lead action level is 30 µg/m³ as an 8-hour TWA. Above this level, employers must implement additional controls.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "What does TWA stand for in occupational exposure monitoring?", options: ["Total Weekly Average", "Time-Weighted Average", "Threshold Warning Alert", "Toxicity Work Assessment"], a: 1, explain: "TWA stands for Time-Weighted Average, which is the average exposure over an 8-hour workday.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "A STEL (Short-Term Exposure Limit) measures exposure over what time period?", options: ["5 minutes", "15 minutes", "30 minutes", "1 hour"], a: 1, explain: "STEL is the maximum average exposure allowed over any 15-minute period during the workday.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "What does IDLH stand for?", options: ["Industrial Daily Limit for Hazardous chemicals", "Immediately Dangerous to Life or Health", "Irreversible Damage Level Hazard", "Individual Daily Labor Hours"], a: 1, explain: "IDLH stands for Immediately Dangerous to Life or Health — the concentration that poses an immediate threat to life or could cause irreversible health effects.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "A ceiling exposure limit means the concentration should:", options: ["Never be exceeded, even momentarily", "Not be exceeded on average over 8 hours", "Not be exceeded for more than 15 minutes", "Not be exceeded for more than 1 hour"], a: 0, explain: "A ceiling value is a concentration that must never be exceeded at any time during the work shift, even momentarily.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Which route of chemical entry occurs when a chemical is breathed in through the nose or mouth?", options: ["Ingestion", "Skin absorption", "Injection", "Inhalation"], a: 3, explain: "Inhalation is the most common route of chemical entry in occupational settings, where chemicals are breathed into the respiratory system.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Eating food or drinking beverages contaminated with chemicals represents which route of entry?", options: ["Inhalation", "Skin absorption", "Ingestion", "Injection"], a: 2, explain: "Ingestion occurs when chemicals enter the body through the mouth, often from hand-to-mouth contact or consuming contaminated food and beverages.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Which GHS pictogram features a skull and crossbones?", options: ["Health hazard pictogram", "Corrosion pictogram", "Acute toxicity pictogram", "Exclamation mark pictogram"], a: 2, explain: "The skull and crossbones GHS pictogram indicates acute toxicity — chemicals that are highly toxic even in small amounts.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "The GHS exclamation mark (!) pictogram indicates:", options: ["Extreme toxicity requiring skull and crossbones", "Less severe hazards like skin/eye irritation or respiratory sensitization", "Flammable materials", "Explosive hazards"], a: 1, explain: "The exclamation mark pictogram is used for less severe hazards such as skin/eye irritants, acute toxicity Category 4, and respiratory irritants.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Which section of an SDS contains first aid measures for chemical exposure?", options: ["Section 2", "Section 3", "Section 4", "Section 6"], a: 2, explain: "Section 4 of an SDS contains First Aid Measures, describing what to do in case of exposure by various routes.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "How many GHS pictograms are there in total?", options: ["6", "7", "8", "9"], a: 3, explain: "There are 9 GHS hazard pictograms: flame, oxidizer, exploding bomb, gas cylinder, corrosion, skull/crossbones, exclamation mark, health hazard, and environment.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "If a worker suspects they have been exposed to a hazardous chemical, they should FIRST:", options: ["Continue working and report at end of shift", "Consult the SDS for first aid instructions and seek medical attention", "Call OSHA immediately", "Wait to see if symptoms develop"], a: 1, explain: "The SDS Section 4 provides specific first aid instructions for exposures. Workers should follow those instructions and seek medical attention promptly.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Which of the following activities on a construction site could expose workers to respirable crystalline silica?", options: ["Painting surfaces", "Jackhammering or cutting concrete", "Installing fiberglass insulation", "Working with wood framing"], a: 1, explain: "Cutting, grinding, or drilling concrete, stone, or masonry releases respirable crystalline silica dust into the air.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Where must Safety Data Sheets (SDS) be kept on a construction site?", options: ["In the project manager's office only", "Accessible to employees during all work shifts", "Locked in a storage room for safekeeping", "Only in digital format on a company website"], a: 1, explain: "SDS must be readily accessible to employees during each work shift in their work area. This can be paper or electronic format.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Which SDS section covers information about reactivity and stability of the chemical?", options: ["Section 7", "Section 9", "Section 10", "Section 12"], a: 2, explain: "Section 10 of the SDS covers Stability and Reactivity, including conditions to avoid and potential hazardous reactions.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Lead poisoning from construction work is most commonly associated with which activity?", options: ["Welding stainless steel", "Demolition or renovation of buildings with lead-based paint", "Installing new PVC plumbing", "Working with concrete"], a: 1, explain: "Disturbing lead-based paint during demolition, renovation, or painting is the primary source of lead exposure in construction.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Which of the following is an example of an engineering control for chemical hazards?", options: ["Wearing a respirator", "Local exhaust ventilation at the source", "Administrative rotation of workers", "Training on chemical hazards"], a: 1, explain: "Local exhaust ventilation captures contaminants at the source before they enter the worker's breathing zone — an engineering control.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "The 'health hazard' GHS pictogram (person with starburst on chest) indicates:", options: ["Acute toxicity", "Carcinogenicity, reproductive toxicity, or serious long-term health effects", "Flammability", "Corrosion to skin"], a: 1, explain: "The health hazard pictogram signals serious health effects such as carcinogenicity, mutagenicity, reproductive toxicity, or organ toxicity.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "What is the primary purpose of OSHA's Hazard Communication standard?", options: ["To ban hazardous chemicals from workplaces", "To ensure workers have the right to know about chemical hazards they may be exposed to", "To set maximum storage amounts for chemicals", "To require chemical manufacturers to reformulate products"], a: 1, explain: "The HazCom standard ensures workers' right to know about chemical hazards, providing information through labels, SDS, and training.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Under HazCom, employers are required to maintain a written hazard communication program that includes:", options: ["A list of hazardous chemicals present in the workplace", "Only emergency contact numbers", "Employee personal medical records", "Equipment maintenance logs"], a: 0, explain: "The written HazCom program must include a list of hazardous chemicals in the workplace, how labels will be handled, and SDS accessibility procedures.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Which SDS section provides information about physical and chemical properties such as boiling point and vapor pressure?", options: ["Section 7", "Section 8", "Section 9", "Section 11"], a: 2, explain: "Section 9 of the SDS covers Physical and Chemical Properties including appearance, odor, boiling point, flash point, and vapor pressure.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Carbon monoxide (CO) is a particular hazard in construction because it is:", options: ["Visible as a yellow gas", "Colorless and odorless, making it undetectable without instruments", "Heavier than air and pools on the ground", "Immediately irritating, warning workers of exposure"], a: 1, explain: "CO is colorless and odorless, so workers cannot detect it without CO monitors, making it especially dangerous in enclosed or poorly ventilated areas.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'mc', q: "Which route of entry is addressed by wearing gloves and coveralls as PPE?", options: ["Inhalation", "Ingestion", "Skin absorption", "Injection"], a: 2, explain: "Gloves and coveralls protect against skin absorption, preventing chemicals from penetrating through the skin into the bloodstream.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },

    // Fill in the Blank (8)
    { type: 'fib', q: "OSHA's Hazard Communication standard is found at 29 CFR 1910.___, and applies to construction via 29 CFR 1926.59.", answer: "1200", accept: ["1910.1200"], explain: "29 CFR 1910.1200 is the HazCom standard. It applies to construction worksites through 29 CFR 1926.59.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'fib', q: "A Safety Data Sheet contains ___ mandatory sections under the GHS system.", answer: "16", accept: ["sixteen"], explain: "GHS requires SDS to have exactly 16 standardized sections to ensure consistent hazard communication worldwide.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'fib', q: "The OSHA PEL for respirable crystalline silica in construction is ___ µg/m³ as an 8-hour TWA.", answer: "50", accept: ["50 µg/m³"], explain: "The silica PEL is 50 micrograms per cubic meter as an 8-hour TWA under 29 CFR 1926.1153.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'fib', q: "Silicosis is an irreversible lung disease caused by inhaling respirable crystalline ___.", answer: "silica", accept: ["silica dust", "crystalline silica"], explain: "Silicosis is caused by inhaling fine particles of crystalline silica, which lodge in the lungs and cause permanent scarring.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'fib', q: "The GHS signal word ___ indicates a more severe hazard than WARNING.", answer: "DANGER", accept: ["Danger"], explain: "DANGER is reserved for the most severe hazard categories, while WARNING is used for less severe hazards.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'fib', q: "IDLH stands for Immediately Dangerous to ___ or Health.", answer: "Life", accept: ["life"], explain: "IDLH (Immediately Dangerous to Life or Health) is the concentration posing an immediate threat requiring immediate evacuation.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'fib', q: "The four routes of chemical entry into the body are inhalation, ingestion, skin absorption, and ___.", answer: "injection", accept: ["injection"], explain: "Injection (through punctures or cuts) is the fourth route of entry, though less common than inhalation and skin absorption.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'fib', q: "The OSHA action level for lead is ___ µg/m³ as an 8-hour TWA.", answer: "30", accept: ["30 µg/m³"], explain: "At 30 µg/m³, employers must implement additional protective measures including medical surveillance for lead-exposed workers.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },

    // Select All That Apply (7)
    { type: 'sa', q: "Which of the following are required elements of a GHS-compliant chemical label? (Select all that apply)", options: ["Product identifier", "Signal word", "Hazard statements", "Manufacturer's stock number"], answers: [0, 1, 2], explain: "GHS labels must include product identifier, signal word, hazard statements, pictograms, precautionary statements, and supplier information. Stock numbers are not required.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'sa', q: "Which of the following are routes of chemical entry into the body? (Select all that apply)", options: ["Inhalation", "Skin absorption", "Static electricity", "Ingestion"], answers: [0, 1, 3], explain: "Inhalation, skin absorption, and ingestion (plus injection) are the four routes of chemical entry. Static electricity is not a route of chemical entry.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'sa', q: "Which of the following activities can expose construction workers to respirable crystalline silica? (Select all that apply)", options: ["Cutting concrete with a dry saw", "Drilling through masonry", "Installing rubber flooring", "Sandblasting with silica sand"], answers: [0, 1, 3], explain: "Cutting/drilling concrete and masonry, and sandblasting with silica sand all release respirable silica dust. Installing rubber flooring does not.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'sa', q: "Which of the following are GHS pictograms? (Select all that apply)", options: ["Flame (flammability)", "Skull and crossbones (acute toxicity)", "Stop sign (prohibited action)", "Exploding bomb (explosive)"], answers: [0, 1, 3], explain: "Flame, skull/crossbones, and exploding bomb are among the 9 GHS pictograms. A stop sign is a prohibition sign, not a GHS pictogram.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'sa', q: "Which of the following are engineering controls for chemical hazard reduction? (Select all that apply)", options: ["Local exhaust ventilation", "General dilution ventilation", "Posting warning signs", "Enclosure of the process"], answers: [0, 1, 3], explain: "Local exhaust, dilution ventilation, and process enclosure are engineering controls. Warning signs are an administrative control.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'sa', q: "Which health hazards are associated with prolonged lead exposure? (Select all that apply)", options: ["Neurological damage", "Kidney damage", "Sunburn", "Reproductive harm"], answers: [0, 1, 3], explain: "Lead exposure can cause neurological damage, kidney damage, and reproductive harm. Sunburn is a physical/UV radiation hazard, not related to lead.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
    { type: 'sa', q: "Which of the following exposure limits may appear on an SDS or in OSHA regulations? (Select all that apply)", options: ["TWA (Time-Weighted Average)", "STEL (Short-Term Exposure Limit)", "Ceiling value", "Maximum Annual Dosage"], answers: [0, 1, 2], explain: "TWA, STEL, and ceiling values are recognized occupational exposure limits. Maximum Annual Dosage is not a standard OSHA/industrial hygiene term.", moduleRef: 8, moduleName: "Health Hazards & Hazard Communication" },
  ],

  9: [
    // Multiple Choice (35)
    { type: 'mc', q: "Stairways or ladders must be provided when there is a change in elevation of at least:", options: ["12 inches", "19 inches", "24 inches", "30 inches"], a: 1, explain: "OSHA requires a stairway or ladder at access points where the elevation change is 19 inches or more.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "The correct angle for a portable straight ladder against a structure follows which rule?", options: ["3:1 rule (1 foot out for every 3 feet up)", "4:1 rule (1 foot out for every 4 feet up)", "5:1 rule (1 foot out for every 5 feet up)", "2:1 rule (1 foot out for every 2 feet up)"], a: 1, explain: "The 4:1 rule requires portable ladders to be placed 1 foot out from the wall for every 4 feet of working height, giving approximately a 75.5° angle.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "Extension ladders must extend at least how far above the upper landing surface?", options: ["1 foot", "2 feet", "3 feet", "4 feet"], a: 2, explain: "Extension ladders must extend at least 3 feet above the upper landing surface to provide a secure handhold when stepping on or off.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "The '3-point contact' rule for ladder climbing requires:", options: ["Three workers on the ladder at once", "Two hands and one foot, OR two feet and one hand on the ladder at all times", "Three rungs of contact at all times", "Contact with three separate safety lines"], a: 1, explain: "Three-point contact means two hands and one foot, or two feet and one hand, maintain contact with the ladder at all times while climbing.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "What is the maximum weight capacity (duty rating) of a Type IA ladder?", options: ["200 lbs", "225 lbs", "250 lbs", "300 lbs"], a: 3, explain: "Type IA ladders have a duty rating of 300 pounds, designated for extra-heavy industrial use.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "What is the duty rating of a Type IAA ladder?", options: ["250 lbs", "300 lbs", "375 lbs", "400 lbs"], a: 2, explain: "Type IAA is the highest duty-rated ladder at 375 pounds, for special extra-heavy industrial applications.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "Which ladder type has a duty rating of 200 pounds?", options: ["Type I", "Type II", "Type III", "Type IA"], a: 2, explain: "Type III ladders have a 200-pound duty rating and are rated for light household use only.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "Why should wooden ladders never be painted?", options: ["Paint makes the rungs slippery", "Paint can hide cracks, splits, and other defects", "Paint adds weight and reduces the duty rating", "OSHA bans painted ladders for aesthetic reasons"], a: 1, explain: "Painting wooden ladders can conceal cracks and defects in the wood that could cause the ladder to fail under load.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "Which type of ladder should be used near electrical hazards?", options: ["Aluminum ladder", "Steel ladder", "Fiberglass ladder", "Wooden ladder"], a: 2, explain: "Fiberglass ladders are non-conductive and should be used near electrical hazards. Metal ladders conduct electricity and are dangerous.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "A stairway with 4 or more risers or a rise of 30 inches or more must have:", options: ["Double handrails on both sides", "At least one handrail", "A safety net underneath", "Anti-slip tape only"], a: 1, explain: "OSHA requires at least one handrail on stairways with 4 or more risers or a rise of 30 inches or more.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "What is the acceptable angle range for stairways from horizontal?", options: ["20-30 degrees", "30-50 degrees", "50-70 degrees", "60-80 degrees"], a: 1, explain: "OSHA specifies that stairways must be installed at angles between 30 and 50 degrees from horizontal.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "In an excavation 4 feet or more deep, a ladder must be within how many feet of lateral travel for workers?", options: ["10 feet", "15 feet", "25 feet", "50 feet"], a: 2, explain: "OSHA requires that means of egress (including ladders) must be within 25 feet of lateral travel for workers in excavations 4 feet or more deep.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "What action must be taken before using a ladder on a construction site?", options: ["Tag the ladder with the user's name", "Inspect the ladder for defects before each use", "Obtain a ladder use permit", "Have a supervisor approve ladder use"], a: 1, explain: "Ladders must be inspected before each use by the user to identify defects such as broken rungs, cracks, or missing hardware.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "On a stepladder, which areas should NEVER be used as a standing surface?", options: ["The lower three rungs", "The top cap and top step", "The middle rungs", "The side rails"], a: 1, explain: "The top cap and top step of a stepladder must never be used as a standing surface — they are not designed for that load and can cause falls.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "Before using a stepladder, workers must ensure it is:", options: ["Leaned against a wall", "Fully opened and the spreader braces are locked", "Partially open for stability", "Secured with rope at the top"], a: 1, explain: "A stepladder must be fully opened with all spreader braces locked in position before anyone uses it.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "Who must supervise the erection, alteration, and dismantling of stairways on construction sites?", options: ["Any experienced worker", "A competent person", "A licensed engineer", "The site superintendent only"], a: 1, explain: "A competent person must supervise the setup and removal of stairways and ladders to ensure they are done safely.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "What is the 4:1 angle for a portable ladder approximately equal to in degrees?", options: ["45 degrees", "60 degrees", "75.5 degrees", "80 degrees"], a: 2, explain: "The 4:1 ratio (1 foot out for every 4 feet up) creates an approximately 75.5-degree angle between the ladder and the ground.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "A ladder placed against a wall must be secured to prevent:", options: ["Workers from over-gripping the rails", "The top from sliding sideways and the base from kicking out", "Paint damage to the wall", "Rust from moisture in the wall"], a: 1, explain: "Ladders must be secured at the top, bottom, or both to prevent the top from sliding sideways and the base from kicking out.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "When climbing a ladder, workers should carry tools and materials by:", options: ["Holding them in one hand while climbing with the other", "Using a tool belt or hoist rope, keeping hands free for 3-point contact", "Stuffing tools in pockets", "Having a coworker carry items up separately"], a: 1, explain: "Tools and materials should be carried using a tool belt, bucket, or hoist so both hands are free for maintaining 3-point contact.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "Which of the following is NOT an acceptable condition for a ladder in use?", options: ["Side rails free of cracks", "All rungs and steps present and secure", "Rungs reinforced with wire as a temporary repair", "Non-slip feet on the base"], a: 2, explain: "Temporary repairs such as wiring broken rungs are not acceptable. Defective ladders must be removed from service and tagged.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "How should a defective ladder be handled on a construction site?", options: ["Tag it 'Do Not Use' and remove from service", "Move it to a less busy area", "Only use it for light loads", "Repair it in the field with available materials"], a: 0, explain: "Defective ladders must be immediately removed from service, tagged with a 'Do Not Use' notice, and repaired or replaced before returning to service.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "The duty rating of a ladder refers to:", options: ["The maximum height the ladder can reach", "The maximum weight load the ladder is designed to support", "The ladder's fire resistance rating", "The ladder's electrical insulation rating"], a: 1, explain: "The duty rating is the maximum safe weight load (in pounds) that a ladder is designed to support, including the worker and all tools/materials.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "Workers on ladders should face the ladder when:", options: ["Descending only", "Ascending only", "Both ascending and descending", "Never — they should always face away"], a: 2, explain: "Workers should always face the ladder and maintain 3-point contact when both ascending and descending.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "Which ladder type has a 250-pound duty rating?", options: ["Type II", "Type I", "Type III", "Type IA"], a: 1, explain: "Type I ladders have a 250-pound duty rating and are designed for heavy-duty industrial use.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "How much should a portable ladder's side rails extend above the top support point?", options: ["At least 1 foot", "At least 2 feet", "At least 3 feet", "At least 4 feet"], a: 2, explain: "Side rails must extend at least 3 feet above the upper landing to provide a handhold for workers getting on and off the ladder.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "What is the maximum spacing between rungs (steps) on a portable ladder?", options: ["10 inches", "12 inches", "16 inches", "18 inches"], a: 1, explain: "OSHA requires rungs, cleats, and steps on portable ladders to be spaced not less than 10 inches and not more than 14 inches apart.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "Can workers use the cross-bracing of a scaffold frame as a means of access?", options: ["Yes, if the cross-bracing is sturdy", "No, cross-bracing should not be used for access", "Only if there is no ladder available", "Yes, but only for descending"], a: 1, explain: "OSHA prohibits using cross-bracing as a means of access or egress on scaffolding. Ladders, stairways, or ramps must be provided.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "Which of the following is required on temporary stairways during construction?", options: ["Permanent handrails on both sides", "At least one handrail when 4+ risers or 30+ inch rise", "Safety nets beneath them", "OSHA inspection tags"], a: 1, explain: "Temporary stairways with 4 or more risers or a 30-inch or greater rise require at least one handrail.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "What is the purpose of non-slip feet on the base of portable ladders?", options: ["To add weight for stability", "To prevent the base from slipping or sliding on the surface", "To protect floor surfaces from scratching", "To meet electrical insulation requirements"], a: 1, explain: "Non-slip feet provide traction on smooth or slippery surfaces, preventing the base of the ladder from kicking out.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "A Type II ladder has a duty rating of:", options: ["200 lbs", "225 lbs", "250 lbs", "300 lbs"], a: 1, explain: "Type II ladders are rated at 225 pounds for medium-duty commercial use.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "In what situation is an aluminum ladder most dangerous to use?", options: ["In wet weather", "Near electrical equipment or power lines", "On uneven ground", "When carrying heavy tools"], a: 1, explain: "Aluminum is an excellent conductor of electricity. Using aluminum ladders near electrical equipment or power lines creates an electrocution hazard.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "Before erecting a ladder near a doorway, a worker should:", options: ["Post a sign on the door only", "Block or guard the door and/or post a warning sign", "Use a shorter ladder so it doesn't block the door", "Lean the ladder away from the door"], a: 1, explain: "Ladders near doorways must have the door blocked, locked, or guarded and a warning sign posted to prevent the door from striking the ladder.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "What type of stairway is most commonly required during multi-story building construction?", options: ["Spiral stairway", "Permanent stairway installed first", "Temporary stairway with handrails", "Ladder system throughout construction"], a: 2, explain: "Temporary stairways with appropriate handrails are commonly required during construction to provide safe access between floors.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "How should ladders be stored when not in use?", options: ["Horizontally on the ground where accessible", "Vertically leaning against a wall", "Horizontally on supports, protected from damage and weather", "In any available location on the job site"], a: 2, explain: "Ladders should be stored horizontally on adequate supports, protected from extreme temperatures, chemicals, and weather to prevent damage.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'mc', q: "When must fall protection be provided for workers on stairways and ladderways?", options: ["Always, regardless of height", "When the fall hazard is 4 feet or more", "Only when working above 10 feet", "Only on exterior stairways"], a: 1, explain: "Fall protection must be provided on stairways and ladder access points when workers could fall 4 feet or more to a lower level.", moduleRef: 9, moduleName: "Stairways & Ladders" },

    // Fill in the Blank (8)
    { type: 'fib', q: "Portable ladders must be placed at a 4:1 angle — ___ foot out for every 4 feet of working height.", answer: "1", accept: ["one"], explain: "The 4:1 rule requires 1 foot of base distance for every 4 feet of vertical height, creating a safe 75.5-degree angle.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'fib', q: "Extension ladders must extend at least ___ feet above the upper landing surface.", answer: "3", accept: ["three"], explain: "The 3-foot extension above the landing provides a handhold for safely stepping on and off the ladder.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'fib', q: "A Type IAA ladder has a duty rating of ___ pounds — the highest of any ladder type.", answer: "375", accept: ["375 lbs", "375 pounds"], explain: "Type IAA is rated at 375 pounds for special extra-heavy industrial applications.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'fib', q: "Stairways and ladders are required when elevation changes reach ___ inches or more.", answer: "19", accept: ["19 inches"], explain: "OSHA requires a stairway or ladder at points of access where the change in elevation is 19 inches or greater.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'fib', q: "Workers in excavations 4 feet or more deep must have egress within ___ feet of lateral travel.", answer: "25", accept: ["25 feet"], explain: "OSHA requires egress to be within 25 feet of lateral travel in excavations 4 feet deep or more.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'fib', q: "Stairways must be installed at angles between 30 and ___ degrees from horizontal.", answer: "50", accept: ["50 degrees"], explain: "OSHA specifies stairway angles must be between 30 and 50 degrees from horizontal for safe use.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'fib', q: "Wooden ladders should never be ___ because it can conceal defects in the wood.", answer: "painted", accept: ["paint"], explain: "Painting wooden ladders hides cracks, splits, and other structural defects that could cause the ladder to fail.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'fib', q: "The three-point contact rule requires maintaining two hands and one foot, or two ___ and one hand on the ladder.", answer: "feet", accept: ["foot"], explain: "Three-point contact (two hands + one foot, OR two feet + one hand) is required at all times when climbing or descending.", moduleRef: 9, moduleName: "Stairways & Ladders" },

    // Select All That Apply (7)
    { type: 'sa', q: "Which of the following are proper practices when using portable ladders? (Select all that apply)", options: ["Maintain 3-point contact at all times", "Face the ladder when ascending and descending", "Carry tools in both hands to work efficiently", "Inspect the ladder before each use"], answers: [0, 1, 3], explain: "3-point contact, facing the ladder, and inspection before use are all correct practices. Carrying tools in both hands prevents maintaining 3-point contact.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'sa', q: "Which types of ladders should NOT be used near electrical hazards? (Select all that apply)", options: ["Aluminum ladders", "Steel ladders", "Fiberglass ladders", "Carbon fiber ladders"], answers: [0, 1], explain: "Aluminum and steel ladders conduct electricity and should not be used near electrical hazards. Fiberglass is non-conductive and appropriate.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'sa', q: "Which ladder defects require removing the ladder from service? (Select all that apply)", options: ["Broken or missing rungs", "Cracks in the side rails", "Faded paint on the rails", "Damaged non-slip feet"], answers: [0, 1, 3], explain: "Broken rungs, cracked rails, and damaged non-slip feet are structural defects requiring the ladder to be removed from service. Faded paint is a cosmetic issue.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'sa', q: "Which of the following ladder duty ratings are used for industrial/heavy-duty applications? (Select all that apply)", options: ["Type III (200 lbs)", "Type IA (300 lbs)", "Type IAA (375 lbs)", "Type I (250 lbs)"], answers: [1, 2, 3], explain: "Type I (250 lbs), Type IA (300 lbs), and Type IAA (375 lbs) are all heavy-duty industrial ratings. Type III (200 lbs) is rated for light household use only.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'sa', q: "Which of the following are proper requirements for stairways on construction sites? (Select all that apply)", options: ["Handrail required when 4+ risers or 30+ inch rise", "Angle between 30-50 degrees from horizontal", "Made of permanent materials only", "Slip-resistant surfaces on treads"], answers: [0, 1, 3], explain: "Handrails, proper angles, and slip-resistant surfaces are OSHA requirements. Temporary stairways may be made of wood or other non-permanent materials.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'sa', q: "Which of the following are acceptable methods to secure a portable ladder at the top? (Select all that apply)", options: ["Tying the ladder to the structure", "Using ladder hooks or brackets", "Leaning it at a steeper angle", "Having a worker hold the base"], answers: [0, 1, 3], explain: "Tying the ladder, using hooks/brackets, or having a worker hold the base are acceptable methods. A steeper angle makes the ladder more dangerous.", moduleRef: 9, moduleName: "Stairways & Ladders" },
    { type: 'sa', q: "Which of the following conditions create ladder fall hazards that must be controlled? (Select all that apply)", options: ["Ladder placed near a doorway", "Ladder on slippery or uneven ground", "Ladder on a dry concrete floor", "Ladder not secured against side movement"], answers: [0, 1, 3], explain: "Doorways, slippery/uneven surfaces, and unsecured ladders all create fall hazards requiring correction. A dry concrete floor with proper non-slip feet is not inherently hazardous.", moduleRef: 9, moduleName: "Stairways & Ladders" },
  ],

  10: [
    // Multiple Choice (35)
    { type: 'mc', q: "Which OSHA regulation governs scaffolding in construction?", options: ["29 CFR 1926 Subpart R", "29 CFR 1926 Subpart L", "29 CFR 1926 Subpart M", "29 CFR 1926 Subpart Q"], a: 1, explain: "29 CFR 1926 Subpart L contains OSHA's scaffolding standards for the construction industry.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "At what height must fall protection be provided for workers on supported scaffolds?", options: ["4 feet", "6 feet", "10 feet", "15 feet"], a: 2, explain: "OSHA requires fall protection for workers on supported scaffolds at heights of 10 feet or more above a lower level.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "At what height must fall protection be provided for workers on suspension scaffolds?", options: ["Any height", "4 feet", "10 feet", "6 feet"], a: 0, explain: "Fall protection is required at ALL heights for workers on suspension (two-point or multi-point) scaffolds.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Supported scaffolds must be designed to support at least how many times the intended load?", options: ["2×", "3×", "4×", "6×"], a: 2, explain: "Supported scaffolds must be capable of supporting 4 times the maximum intended load without failure.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Suspension scaffolds must be designed with a safety factor of how many times the intended load?", options: ["2×", "4×", "6×", "8×"], a: 2, explain: "Suspension scaffolds must be designed to support 6 times the maximum intended load. Wire ropes must also have a 6× safety factor.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Who is responsible for designing the scaffold system before construction begins?", options: ["Competent person", "Qualified person", "Site superintendent", "Safety officer"], a: 1, explain: "A qualified person (one with appropriate recognized degree, certificate, or professional standing) must design scaffold systems.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Who must inspect scaffolding before each work shift?", options: ["Any available worker", "Qualified person", "Competent person", "OSHA inspector"], a: 2, explain: "A competent person must inspect scaffolding before each work shift and after any event that could affect its structural integrity.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Scaffold planks must extend beyond end supports by how much?", options: ["3-6 inches", "6-18 inches", "12-24 inches", "18-24 inches"], a: 1, explain: "OSHA requires scaffold planks to extend 6 to 18 inches past the end supports (but not more than 18 inches) to prevent tipping.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "The top guardrail on scaffolding must be between which heights?", options: ["36-42 inches", "38-45 inches", "40-50 inches", "42-48 inches"], a: 1, explain: "OSHA requires scaffold guardrail top rails to be installed between 38 and 45 inches above the platform surface.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Scaffold toeboards must be at least how high?", options: ["2 inches", "3 inches", "3.5 inches", "4 inches"], a: 2, explain: "Toeboards on scaffolding must be at least 3.5 inches high to prevent tools and materials from rolling off the edge.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Workers must NOT access scaffolding by using:", options: ["Portable ladders", "Built-in scaffold ladders", "Cross-bracing", "Scaffold stairways"], a: 2, explain: "Cross-bracing must not be used as a means of access or egress on scaffolding. Ladders, stairways, or ramps must be provided.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Scaffolding must not be erected within how many feet of energized power lines?", options: ["3 feet", "5 feet", "10 feet", "15 feet"], a: 2, explain: "Scaffolds must not be erected within 10 feet of energized power lines unless the lines are de-energized and grounded or insulated.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What color tag indicates that a scaffold is safe to use?", options: ["Red", "Yellow", "Green", "Orange"], a: 2, explain: "Green scaffold tags indicate the scaffold has been inspected and is safe for use. Yellow means limited use, and red means do not use.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What does a RED scaffold tag mean?", options: ["The scaffold is safe to use", "The scaffold can be used with restrictions", "Do not use — the scaffold is unsafe", "The scaffold is under construction"], a: 2, explain: "A red scaffold tag means the scaffold must NOT be used. It indicates an unsafe condition requiring correction before the scaffold can be put into service.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What does a YELLOW scaffold tag indicate?", options: ["The scaffold is fully safe to use", "The scaffold has limitations and conditions for use", "The scaffold is condemned", "The scaffold is in the process of being built"], a: 1, explain: "A yellow scaffold tag indicates the scaffold can be used only under specific conditions or limitations as noted on the tag.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Who may erect, alter, or dismantle scaffolding?", options: ["Any construction worker on the project", "Workers under supervision of a competent person", "Only licensed scaffold erectors", "Workers certified by the scaffold manufacturer"], a: 1, explain: "Scaffolding must be erected, altered, and dismantled under the supervision of a competent person to ensure it is done safely.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What is the minimum width of a scaffold platform for most construction work?", options: ["12 inches", "18 inches", "24 inches", "36 inches"], a: 2, explain: "OSHA requires scaffold platforms to be at least 18 inches wide. For most work, platforms should be planked to the full width of the scaffold.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "The mid-rail on scaffold guardrails must be positioned:", options: ["At 21 inches from the platform", "Midway between the top rail and platform", "At 30 inches from the platform", "Anywhere between 18-36 inches"], a: 1, explain: "The mid-rail must be positioned midway between the top rail and the platform surface to prevent workers from falling through the gap.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "For suspension scaffolds, the wire rope used must have a safety factor of:", options: ["2×", "4×", "6×", "8×"], a: 2, explain: "Wire ropes used on suspension scaffolds must have a safety factor of at least 6, meaning they must support 6 times the maximum intended load.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What training must workers receive before working on scaffolding?", options: ["Only fall hazard training", "Fall hazards, falling objects, electrical hazards, and scaffold-specific hazards", "A 10-hour OSHA course", "Certification from a scaffold manufacturer"], a: 1, explain: "Workers must be trained in fall hazards, protection from falling objects, electrical hazards, and the specific hazards of the scaffold they will use.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What must be provided to protect people below scaffolding from falling objects?", options: ["Hard hats only", "Toeboards, screens, or barricades to prevent objects from falling", "Warning signs at ground level only", "Safety nets 10 feet below the scaffold"], a: 1, explain: "Toeboards, screens, canopy structures, or barricades must be used to protect people below scaffolding from falling tools and materials.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What is a 'qualified person' in the context of scaffolding?", options: ["Anyone with 5+ years of construction experience", "A person with recognized degree, certificate, professional standing, or knowledge to design scaffold systems", "Any OSHA-10 certified worker", "A worker appointed by the employer"], a: 1, explain: "A qualified person has the recognized training and knowledge (degree, certification, or professional standing) to perform specific design-related tasks.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What is a 'competent person' in scaffolding operations?", options: ["A person with a college degree in engineering", "One who can identify existing and predictable hazards and has authority to eliminate them", "Any licensed contractor", "A person who has built scaffolds before"], a: 1, explain: "A competent person can identify existing and predictable scaffold hazards and has the authority to take prompt corrective action.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "When must a scaffold be re-inspected by a competent person?", options: ["Only at the beginning of the job", "Before each shift and after any occurrence that could affect structural integrity", "Once a week", "Whenever a worker requests an inspection"], a: 1, explain: "Scaffolds must be inspected before each work shift and after any event (such as a storm, impact, or loading change) that could affect structural integrity.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Which of the following must be considered when determining if a scaffold platform is safe for use?", options: ["The color of the scaffold frame", "Maximum intended load, scaffold capacity, and condition of components", "Brand name of the scaffold manufacturer", "Age of the scaffold"], a: 1, explain: "Safe scaffold use requires evaluating the maximum intended load, the scaffold's rated capacity, and the condition of all structural components.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What type of scaffold is suspended from an overhead structure using wire ropes or cables?", options: ["Supported scaffold", "Pump jack scaffold", "Suspension scaffold", "Mobile scaffold"], a: 2, explain: "Suspension scaffolds are hung from an overhead structure using wire ropes, cables, or chains and require a 6× safety factor.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "A mobile scaffold (rolling tower) must have its casters locked when:", options: ["The scaffold is being moved", "Workers are on the platform", "It is stored overnight", "The scaffold is below 10 feet high"], a: 1, explain: "Casters on mobile scaffolds must be locked whenever workers are on the platform to prevent the scaffold from rolling unexpectedly.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Overloading a scaffold can result in which hazard?", options: ["Scaffold discoloration", "Structural failure and collapse", "Increased inspection frequency", "Void in equipment warranty"], a: 1, explain: "Exceeding a scaffold's rated capacity can cause structural failure and collapse, endangering workers on and below the scaffold.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Which of the following describes a 'tube and coupler' scaffold?", options: ["A prefabricated modular system with frames", "A scaffold built with individual tubes held together by couplers/clamps", "A scaffold hanging from ropes on a building", "A scissor lift mechanism"], a: 1, explain: "Tube and coupler scaffolds use individual steel tubes (pipes) connected by various types of clamps (couplers) for maximum versatility.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What is the maximum safe working load of a light-duty scaffold per square foot?", options: ["15 lbs/sq ft", "25 lbs/sq ft", "50 lbs/sq ft", "75 lbs/sq ft"], a: 1, explain: "Light-duty scaffolds are rated at 25 lbs per square foot. Medium-duty is 50 lbs/sq ft and heavy-duty is 75 lbs/sq ft.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "Scaffold tags should be placed in a location that is:", options: ["Hidden from workers to prevent tampering", "Visible to workers before they access the scaffold", "Kept by the competent person at all times", "Posted only at the scaffold entrance"], a: 1, explain: "Scaffold tags must be visible to workers before they access the scaffold so they know whether it is safe to use, requires restrictions, or is off-limits.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What is the primary purpose of a toeboard on a scaffold?", options: ["To prevent workers from falling off the edge", "To prevent tools and materials from falling off and striking workers below", "To support the mid-rail guardrail", "To strengthen the scaffold platform"], a: 1, explain: "Toeboards prevent tools, materials, and debris from rolling off scaffold platforms and falling on workers below.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "When building a scaffold adjacent to a structure, what must be considered regarding power lines?", options: ["Power lines have no effect on scaffold safety", "The scaffold must stay at least 10 feet from energized power lines", "Workers must wear extra insulation near power lines", "Power lines only matter for suspension scaffolds"], a: 1, explain: "All scaffold types must maintain at least 10 feet of clearance from energized power lines to prevent electrocution.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What is a pump jack scaffold?", options: ["A scaffold suspended by motorized pulleys", "A scaffold supported by a pump-operated jack mechanism on vertical poles", "A scissor lift used for heavy loads", "A mobile scaffold with hydraulic casters"], a: 1, explain: "A pump jack scaffold uses a mechanism that can be pumped to raise and lower the platform along vertical poles attached to the structure.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'mc', q: "What must be done before any scaffold work begins at the start of each shift?", options: ["File a permit with OSHA", "Have the competent person inspect the scaffold", "Replace all planks with new ones", "Test-load the scaffold with 6× the intended load"], a: 1, explain: "Before each shift begins, a competent person must inspect the scaffold to ensure it remains in safe condition for use.", moduleRef: 10, moduleName: "Scaffolding" },

    // Fill in the Blank (8)
    { type: 'fib', q: "OSHA scaffolding standards for construction are found in 29 CFR 1926 Subpart ___.", answer: "L", accept: ["subpart L", "l"], explain: "29 CFR 1926 Subpart L contains all OSHA scaffolding requirements for the construction industry.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'fib', q: "Supported scaffolds must support ___ times the maximum intended load.", answer: "4", accept: ["four", "4x", "four times"], explain: "The 4× safety factor for supported scaffolds means the scaffold must be capable of supporting 4 times the maximum load that will be placed on it.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'fib', q: "Fall protection on supported scaffolds is required at heights of ___ feet or more.", answer: "10", accept: ["ten", "10 feet"], explain: "Workers on supported scaffolds must have fall protection (guardrails or PFAS) when working 10 feet or more above the lower level.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'fib', q: "Scaffold planks must extend ___ to 18 inches past the end supports.", answer: "6", accept: ["six", "6 inches"], explain: "OSHA requires planks to extend a minimum of 6 inches and a maximum of 18 inches past their end supports to prevent tipping.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'fib', q: "A ___ scaffold tag means the scaffold is safe to use without restrictions.", answer: "green", accept: ["Green"], explain: "Green tags indicate a scaffold has been inspected and approved as safe for use. Yellow = limited use, Red = do not use.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'fib', q: "Scaffolding must not be erected within ___ feet of energized overhead power lines.", answer: "10", accept: ["ten", "10 feet"], explain: "OSHA requires all scaffolding to maintain at least 10 feet of clearance from energized power lines.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'fib', q: "The top guardrail on scaffolding must be between 38 and ___ inches above the platform surface.", answer: "45", accept: ["45 inches", "forty-five"], explain: "OSHA specifies that scaffold top guardrails must be installed between 38 and 45 inches above the work platform.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'fib', q: "Toeboards on scaffolding must be at least ___ inches high.", answer: "3.5", accept: ["3½", "three and a half", "3.5 inches"], explain: "A minimum toeboard height of 3.5 inches is required to keep tools and materials from rolling off scaffold platforms.", moduleRef: 10, moduleName: "Scaffolding" },

    // Select All That Apply (7)
    { type: 'sa', q: "Which of the following must workers be trained on before working on scaffolding? (Select all that apply)", options: ["Fall hazards", "Falling object hazards", "Scaffold manufacturing processes", "Electrical hazards near scaffolds"], answers: [0, 1, 3], explain: "Workers must be trained on fall hazards, falling objects, and electrical hazards. Manufacturing processes are not required training content.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'sa', q: "Which of the following are acceptable means of access to scaffold platforms? (Select all that apply)", options: ["Portable ladders", "Built-in scaffold ladder frames", "Cross-bracing", "Scaffold stairway systems"], answers: [0, 1, 3], explain: "Ladders, built-in ladder frames, and stairways are acceptable access methods. Cross-bracing must not be used for access.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'sa', q: "Which components are required elements of a scaffold guardrail system? (Select all that apply)", options: ["Top rail (38-45 inches)", "Mid-rail (midway between top rail and platform)", "Bottom rail (6 inches from platform)", "Toeboard (minimum 3.5 inches high)"], answers: [0, 1, 3], explain: "A scaffold guardrail system requires a top rail, mid-rail, and toeboard. There is no 'bottom rail' requirement — the toeboard serves the bottom protection purpose.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'sa', q: "Which events require re-inspection of scaffolding by a competent person? (Select all that apply)", options: ["Before each work shift", "After a severe storm", "After a scaffold component is impacted by equipment", "Whenever a new worker arrives on site"], answers: [0, 1, 2], explain: "Re-inspection is required before each shift and after events like storms or impacts that could affect structural integrity. New workers arriving alone does not trigger an inspection requirement.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'sa', q: "Which of the following scaffold hazards must be controlled to protect workers? (Select all that apply)", options: ["Fall hazards from scaffold platforms", "Falling objects from scaffold platforms", "Scaffold color fading in sunlight", "Electrocution from nearby power lines"], answers: [0, 1, 3], explain: "Falls, falling objects, and electrical hazards from power lines are all real scaffold hazards requiring control. Color fading is not a safety hazard.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'sa', q: "Which of the following describe scaffold 'competent person' responsibilities? (Select all that apply)", options: ["Inspecting scaffolding before each shift", "Supervising scaffold erection and dismantling", "Designing the scaffold structural system", "Identifying and correcting scaffold hazards"], answers: [0, 1, 3], explain: "Competent persons inspect, supervise erection/dismantling, and correct hazards. Designing the structural system is the responsibility of the qualified person.", moduleRef: 10, moduleName: "Scaffolding" },
    { type: 'sa', q: "Which of the following are requirements for scaffold planking? (Select all that apply)", options: ["Extend 6-18 inches past end supports", "Support 4× the intended load for supported scaffolds", "Overlap by a minimum of 12 inches when spliced", "Be free from defects that could cause failure"], answers: [0, 1, 3], explain: "Planks must extend 6-18 inches, the scaffold must support 4× the load, and planks must be defect-free. When planks overlap, the minimum overlap is 12 inches.", moduleRef: 10, moduleName: "Scaffolding" },
  ],
};
